CItem* SubMap::ItemSpawn(const SItemGrid *pItemInfo, std::int32_t lPosX, std::int32_t lPosY, char chSpawnType,
						 std::int32_t lFromEntityID, std::int32_t lProtChaID, std::int32_t lProtChaHandle, std::int32_t lProtTime, std::int32_t lOnTick,
						 CEvent	*pCEvent)
{
	CItem *pCItem;
	CItemRecord *pCItemRec;

	pCItemRec = GetItemRecordInfo(pItemInfo->sID);
	if (!pCItemRec)
		return 0;
	pCItem = g_pGameApp->GetNewItem();
	if (!pCItem)
		return 0;
	memcpy(&pCItem->m_SGridContent, pItemInfo, sizeof(SItemGrid));
	//if (pCItemRec->chExclusiveID) // ID0
	//{
	//	pItemInfo->SetDBParam(-1, 0);
	//}
	//else
	//	pItemInfo->SetDBParam(-1, 0);
	pCItem->m_pCItemRecord = pCItemRec;
	if (pCEvent)
		pCItem->SetEvent(*pCEvent);
	pCItem->SetName(pCItemRec->szName.c_str());
	pCItem->SetCat(pItemInfo->sID);
	pCItem->m_ID = g_pGameApp->m_Ident.GetID();
	pCItem->SetSpawnType(chSpawnType);
	pCItem->SetFromID(lFromEntityID);
	Corsairs::Util::Square SShape = {{lPosX, lPosY}, 0};
	pCItem->SetAngle(rand() / 360);
	pCItem->SetEyeshotAbility(false);
	if (!Enter(&SShape, pCItem))
	{
		pCItem->Free();
		return 0;
	}
	pCItem->SetSpawnType(enumITEM_APPE_NATURAL);
	pCItem->SetProtCha(lProtChaID, lProtChaHandle);
	if (lProtTime == -1)
		pCItem->SetProtOnTick(0);
	else if (lProtTime > 0)
		pCItem->SetProtOnTick(lProtTime);
	if (lOnTick == -1)
		pCItem->SetOnTick(0);
	if (lOnTick > 0)
		pCItem->SetOnTick(lOnTick);


	char szLogName[defLOG_NAME_LEN] = "";
	{
		auto _s = std::format("{}+{}", pCItem->GetName(), pCItem->GetID());
		std::strncpy(szLogName, _s.c_str(), sizeof(szLogName) - 1);
		szLogName[sizeof(szLogName) - 1] = 0;
	}
	pCItem->SetLogName(szLogName);

	return pCItem;
}

