CCharacter* SubMap::ChaSpawn(std::int32_t lChaInfoID, Corsairs::Common::Character::EChaCtrlType chCtrlType, int16_t sAngle, Corsairs::Util::Point *pSPos, bool bEyeshotAbility, const char *cszChaName, const long clSearchRadius)
{
	CCharacter	*pCCha;
	CChaRecord	*pCChaRecord;

	if (!IsValidPos(pSPos->X, pSPos->Y))
		return 0;

	pCChaRecord = GetChaRecordInfo(lChaInfoID);
	if (pCChaRecord == NULL)
		return 0;
	pCCha = g_pGameApp->GetNewCharacter();
	if (!pCCha)
		return 0;
	pCCha->m_CChaAttr.Init(lChaInfoID);
	if (chCtrlType == EChaCtrlType::NONE)
		chCtrlType = pCChaRecord->CtrlType;
	pCCha->setAttr(ATTR_CHATYPE, chCtrlType);
	pCCha->m_pCChaRecord = pCChaRecord;
	pCCha->SetCat((short)(pCCha->m_pCChaRecord->Id));
	pCCha->SetID(g_pGameApp->m_Ident.GetID());
	pCCha->m_AIType = (BYTE)(pCChaRecord->AiNo);
	pCCha->m_sChaseRange = (short)(pCChaRecord->CDis);
	pCCha->SetAngle(sAngle);
	Corsairs::Util::Square SShape = {*pSPos, pCCha->m_pCChaRecord->Radii};
	if (!cszChaName)
		pCCha->_name = pCCha->m_pCChaRecord->DataName;
	else
		pCCha->_name = cszChaName;
	pCCha->SetEyeshotAbility(bEyeshotAbility);
	if (pCChaRecord->Dormancy > 0)
		pCCha->SetExistState(enumEXISTS_SLEEPING);
	if (!Enter(&SShape, pCCha, clSearchRadius))
	{
		pCCha->Free();
		return 0;
	}
	Corsairs::Util::Circle l_STerritory = {*pSPos, 500};
	pCCha->SetTerritory(l_STerritory);

	// 
	pCCha->EnrichSkillBag();

	char szLogName[defLOG_NAME_LEN] = "";
	{
		auto _s = std::format("Cha-{}+{}", pCCha->GetName(), pCCha->GetID());
		std::strncpy(szLogName, _s.c_str(), sizeof(szLogName) - 1);
		szLogName[sizeof(szLogName) - 1] = 0;
	}
	pCCha->SetLogName(szLogName);

	// pCCha->ResetLifeTime(5000);
	
	return pCCha;
}

