void SubMap::Notice(const char *szString)
{
	//  :   
	auto WtPk = Corsairs::Net::Msg::serialize(Corsairs::Net::Msg::McSysInfoMessage{szString});

	std::vector<CPlayer*> recipients;
	CEyeshotCell	*pCEyeCell;
	CCharacter		*pCCha;
	std::int32_t			lChaCount, lChaNum;
	m_CEyeshotCellL.BeginGet();
	while (pCEyeCell = m_CEyeshotCellL.GetNext())
	{
		lChaCount = 0;
		lChaNum = pCEyeCell->GetChaNum();
		pCCha = pCEyeCell->m_pCChaL;
		while (pCCha)
		{
			if (++lChaCount > lChaNum)
			{
				//LG("", "[%d,%d] %d\n", pCEyeCell->m_sPosX, pCEyeCell->m_sPosY, lChaNum);
				ToLogService("errors", LogLevel::Error, "eyeshot cell[{},{}]fact entity nubmer{}", pCEyeCell->m_sPosX, pCEyeCell->m_sPosY, lChaNum);
				break;
			}

			if(pCCha->IsPlayerFocusCha())
			{
				recipients.push_back(pCCha->GetPlayer());

				if (!pCCha->GetSubMap())
					//LG("", " %s(%s)[%d,%d] \n",
					ToLogService("errors", LogLevel::Error, "in the wind map notify character {}({})[{},{}] 's map is empty",
						pCCha->GetLogName(), pCCha->GetPlyCtrlCha()->GetLogName(), pCCha->GetPos().X, pCCha->GetPos().Y);
			}

			if (pCCha->m_pCEyeshotCellNext)
				pCCha = pCCha->m_pCEyeshotCellNext->IsCharacter();
			else
				pCCha = 0;
		}
	}

	SENDTOCLIENT(WtPk, recipients);
}

std::int32_t SubMap::CountEyeshotPlyActiveNum(std::int32_t lCellX, std::int32_t lCellY)
{
	std::int32_t	lActNum = 0;

	CCharacter		*pCCha;
	std::int32_t			lChaCount = 0, lChaNum;
	pCCha = m_pCEyeshotCell[lCellY][lCellX].m_pCChaL;
	lChaNum = m_pCEyeshotCell[lCellY][lCellX].GetChaNum();
	while (pCCha)
	{
		if (++lChaCount > lChaNum)
		{
			//LG("", "[%d,%d] %d\n", lCellX, lCellY, lChaNum);
			ToLogService("errors", LogLevel::Error, "account eyeshot cell [{},{}]'s activation character numberpractice character number{}", lCellX, lCellY, lChaNum);
			break;
		}

		if(pCCha->IsPlayerCha())
		{
			if (pCCha->GetEyeshotAbility())
				lActNum++;
		}

		if (pCCha->m_pCEyeshotCellNext)
			pCCha = pCCha->m_pCEyeshotCellNext->IsCharacter();
		else
			pCCha = 0;
	}

	return lActNum;
}

