bool SubMap::IsMoveAble(Entity *pCEnt, std::int32_t lPosX, std::int32_t lPosY)
{
	CFightAble	*pCCha = 0;
	if (!pCEnt || !(pCCha = pCEnt->IsFightAble()))
		return false;
	return ::IsMoveAble(static_cast<EChaCtrlType>(pCCha->m_CChaAttr.GetAttr(ATTR_CHATYPE)), pCCha->m_pCChaRecord->Territory, pCEnt->GetAreaAttr()); //
}

BOOL SubMap::LoadEventEntity()
{
	g_pScriptMap = this;
	char szMapEntity[256];
	{
		auto _s = std::format("{}\\{}{}", GetName(), GetName(), "entity.lua");
		std::strncpy(szMapEntity, _s.c_str(), sizeof(szMapEntity) - 1);
		szMapEntity[sizeof(szMapEntity) - 1] = 0;
	}
	ReloadEntity( GetResPath(szMapEntity) );
	return TRUE;
}

BOOL SubMap::LoadNpc()
{
	if( m_pCMapRes->m_pNpcSpawn->Load( *this ) == -1 )
	{
		ThrowRuntimeError(RES_STRING(GM_SUBMAP_CPP_00003));
		return FALSE;
	}

	return TRUE;
}

CNpcRecord* SubMap::GetNpcInfo( USHORT sNpcID )
{
	if( m_pCMapRes->m_pNpcSpawn )
	{
		return m_pCMapRes->m_pNpcSpawn->GetNpcInfo( sNpcID );
	}
	return NULL;
}

