void SubMap::MoveInStateCell(CCharacter* pCCha, const Corsairs::Util::Point &SSrcPos, const Corsairs::Util::Point &STarPos)
{
	Corsairs::Util::Point	l_src = SSrcPos;
	Corsairs::Util::Point	l_dst = STarPos;
	std::int32_t	lRadius = pCCha->GetRadius();
	const Corsairs::Util::Rect l_srcTerr = GetHoldStateCell(l_src, lRadius);
	const Corsairs::Util::Rect l_dstTerr = GetHoldStateCell(l_dst, lRadius);

	if (l_src == l_dst)
		return;

	std::int32_t		x, y;
	// 
	CStateCellNode	*pCNode = pCCha->m_pCStateCellHead;
	if (pCCha)
	{
		while (pCNode)
		{
			StateCellDelCha(pCNode->m_pCStateCell->m_sPosX, pCNode->m_pCStateCell->m_sPosY, pCNode->m_pCChaNode);
			pCNode = pCNode->m_pCNext;
		}
	}
	// 
	for (y = l_dstTerr.LeftTop.Y; y <= l_dstTerr.RightBottom.Y; y++)
	{
		for (x = l_dstTerr.LeftTop.X; x <= l_dstTerr.RightBottom.X; x++)
		{
			if (y != l_dst.Y || x != l_dst.X)
			{
				//StateCellAddCha(x, y, pCCha, false); // 
			}
			else
				StateCellAddCha(x, y, pCCha, true); // 
		}
	}
}

void SubMap::MoveInMapMask(CCharacter* pCCha, const Corsairs::Util::Point &SSrcPos, const Corsairs::Util::Point &STarPos)
{
	if (!pCCha->IsPlayerCha())
		return;
	Corsairs::Util::Point	l_src, l_dst;

	long	lStep = 4 * 100;
	l_src.X = SSrcPos.X / lStep;
	l_src.Y = SSrcPos.Y / lStep;
	l_dst.X = STarPos.X / lStep;
	l_dst.Y = STarPos.Y / lStep;
	if (l_src != l_dst)
		pCCha->GetPlayer()->RefreshMapMask(GetName(), STarPos.X / 100, STarPos.Y / 100);
}

