// bActiveMgr 
//=============================================================================
bool SubMap::Enter(Corsairs::Util::Square* pSEntShape, Entity * ent, const int32_t clSearchRadius)
{
	ent->SetInitShape(*pSEntShape);

	const	Corsairs::Util::Point l_pt = pSEntShape->Centre;
	bool	l_retval = true;
	Corsairs::Util::Point	l_pt2, l_pt1;

	l_pt1 = l_pt;
	Corsairs::Util::Rect	l_rect = GetEyeshot(l_pt1);
	long	lStep = pSEntShape->Radius;

	if (lStep == 0) // 0
		lStep = 40;

	//
	ent->m_submap	=this;
	long l_xdlt	=0,l_ydlt	=0;
	
	if (clSearchRadius > 0)
	{
		if(ent->overlap(l_xdlt,l_ydlt))
		{
			long l_dist =0;
			bool l_overflag =true;
			while(l_overflag) //
			{
				l_dist++;
				for(short dir=0;dir<4;dir++){
					l_pt1	=l_pt;
					//long l_radius	=2 * lStep * l_dist;
					long l_radius	=GetBlockCellWidth() * l_dist;
					if(l_radius >clSearchRadius){
						l_retval	=false;
						l_overflag	=false;
						break;
					}
					l_pt1.Move(dir*90,l_radius);
					l_pt2	=l_pt1;
					l_rect =GetEyeshot(l_pt2);

					ent->SetPos(l_pt1);
					l_xdlt	=l_ydlt		=0;

					if(!(l_overflag =ent->overlap(l_xdlt,l_ydlt))){
						l_retval	=true;
						break;
					}
				}
			}
		}
	}
	else if (clSearchRadius == 0)
	{
		if(ent->overlap(l_xdlt,l_ydlt))
			l_retval = false;
	}
	else // 
	{}
	//beginsee
	if(l_retval)
	{
		bool	bActive = ent->GetEyeshotAbility();

		for(long y =l_rect.LeftTop.Y;y <=l_rect.RightBottom.Y;y++)
		{
			for(long x =l_rect.LeftTop.X;x <=l_rect.RightBottom.X;x++)
			{
				if (bActive)
					ActiveEyeshotCell(x, y);

				m_pCEyeshotCell[y][x].EnterEyeshot(ent);
			}
		}

		//
		ent->RefreshArea();
		Add(ent);		
		ent->m_lastpos	=ent->GetPos();
	}
	else
		ent->m_submap = 0;


	return l_retval;
}

// Enter
bool SubMap::EnsurePos(Corsairs::Util::Square* pSEntShape, Entity * ent, const int32_t clSearchRadius)
{
	ent->SetInitShape(*pSEntShape);

	const	Corsairs::Util::Point l_pt = pSEntShape->Centre;
	bool	l_retval = true;
	Corsairs::Util::Point	l_pt2, l_pt1;

	l_pt1 = l_pt;
	long	lStep = pSEntShape->Radius;

	if (lStep == 0) // 0
		lStep = 40;

	//
	ent->m_submap	=this;
	long l_xdlt	=0,l_ydlt	=0;
	
	if (clSearchRadius > 0)
	{
		if(ent->overlap(l_xdlt,l_ydlt))
		{
			long l_dist =0;
			bool l_overflag =true;
			while(l_overflag) //
			{
				l_dist++;
				for(short dir=0;dir<6;dir++){
					l_pt1	=l_pt;
					long l_radius	=2 * lStep * l_dist;
					if(l_radius >clSearchRadius){
						l_retval	=false;
						l_overflag	=false;
						break;
					}
					l_pt1.Move(dir*60,l_radius);
					l_pt2	=l_pt1;

					ent->SetPos(l_pt1);
					l_xdlt	=l_ydlt		=0;

					if(!(l_overflag =ent->overlap(l_xdlt,l_ydlt))){
						l_retval	=true;
						break;
					}
				}
			}
		}
	}
	else if (clSearchRadius == 0)
	{
		if(ent->overlap(l_xdlt,l_ydlt))
			l_retval = false;
	}
	else // 
	{}
	//beginsee
	if(!l_retval)
		ent->m_submap = 0;


	return l_retval;
}

//=============================================================================
// 
// bActiveMgr 
//=============================================================================
void SubMap::GoOut(Entity * ent)
{
	DBG_ASSERT_ENTITY(ent);
#if defined(_DEBUG)
	const void* l_dbgEnt = static_cast<const void*>(ent);
	const char* l_dbgName = ent->GetLogName();
#endif
	Corsairs::Util::Point l_pt =ent->GetShape().Centre;
	Corsairs::Util::Rect l_rect =GetEyeshot(l_pt);
	//
	Delete(ent);
	//endsee

	bool	bActive = ent->GetEyeshotAbility();

	for(long y =l_rect.LeftTop.Y;y <=l_rect.RightBottom.Y;y++)
	{
		for(long x =l_rect.LeftTop.X;x <=l_rect.RightBottom.X;x++)
		{
			if (bActive)
				InactiveEyeshotCell(x, y);

			m_pCEyeshotCell[y][x].OutEyeshot(ent);
		}
	}

#if defined(_DEBUG)
	// Форензик-скан: пробегаем ВСЕ клетки карты — ent должен быть
	// нигде (ни в m_pCChaL, ни в m_pCItemL, ни в next/last-связях).
	// Если найден — это root-cause "item остался после pickup":
	// Delete удалил его только из одного cell, а он был ещё где-то.
	const long l_lins = GetEyeshotCellLin();
	const long l_cols = GetEyeshotCellCol();
	for (long cy = 0; cy < l_lins; ++cy)
	{
		for (long cx = 0; cx < l_cols; ++cx)
		{
			CEyeshotCell& l_cell = m_pCEyeshotCell[cy][cx];
			for (const Entity* p = l_cell.m_pCChaL; p; p = p->m_pCEyeshotCellNext)
			{
				if (p == ent)
				{
					ToLogService("errors", LogLevel::Error,
						"SubMap::GoOut LEAK: ent={} name='{}' still in cell[{}][{}].m_pCChaL after Delete+OutEyeshot. "
						"Initial pos=[{},{}] eyeshot-rect=[{},{}..{},{}].",
						l_dbgEnt, l_dbgName, cy, cx, l_pt.X, l_pt.Y,
						l_rect.LeftTop.X, l_rect.LeftTop.Y, l_rect.RightBottom.X, l_rect.RightBottom.Y);
					break;
				}
			}
			for (const Entity* p = l_cell.m_pCItemL; p; p = p->m_pCEyeshotCellNext)
			{
				if (p == ent)
				{
					ToLogService("errors", LogLevel::Error,
						"SubMap::GoOut LEAK: ent={} name='{}' still in cell[{}][{}].m_pCItemL after Delete+OutEyeshot. "
						"Initial pos=[{},{}] eyeshot-rect=[{},{}..{},{}].",
						l_dbgEnt, l_dbgName, cy, cx, l_pt.X, l_pt.Y,
						l_rect.LeftTop.X, l_rect.LeftTop.Y, l_rect.RightBottom.X, l_rect.RightBottom.Y);
					break;
				}
			}
		}
	}
#endif

	ent->m_submap =0;
}

// 
void SubMap::RefreshEyeshot(Entity *pCEnt, bool bEyeshot, bool bHide, bool bShow)
{
	Corsairs::Util::Point l_pt = pCEnt->GetShape().Centre;
	Corsairs::Util::Rect l_rect = GetEyeshot(l_pt);

	for(long y =l_rect.LeftTop.Y;y <=l_rect.RightBottom.Y;y++)
	{
		for(long x =l_rect.LeftTop.X;x <=l_rect.RightBottom.X;x++)
		{
			m_pCEyeshotCell[y][x].RefreshEyeshot(pCEnt, bEyeshot, bHide, bShow);
		}
	}
}

Corsairs::Util::Rect SubMap::GetEyeshot(Corsairs::Util::Point &pt)const
{
	const Corsairs::Util::Rect	&m_area = GetRange();
	Corsairs::Util::Rect l_rect;
	pt.X	=(pt.X - m_area.LeftTop.X)/GetEyeshotCellWidth();
	pt.Y	=(pt.Y - m_area.LeftTop.Y)/GetEyeshotCellHeight();
	l_rect.LeftTop.X	=max(pt.X -GetEyeshotWidth(),0);
	l_rect.LeftTop.Y	=max(pt.Y -GetEyeshotWidth(),0);
	l_rect.RightBottom.X	=min(pt.X +GetEyeshotWidth(),GetEyeshotCellCol() -1);
	l_rect.RightBottom.Y	=min(pt.Y +GetEyeshotWidth(),GetEyeshotCellLin() -1);
	return l_rect;
}

Corsairs::Util::Rect SubMap::GetEyeshot(short sMgrUnitX, short sMgrUnitY)const
{
	Corsairs::Util::Rect	l_rect;

	l_rect.LeftTop.X = max(sMgrUnitX - GetEyeshotWidth(), 0);
	l_rect.LeftTop.Y = max(sMgrUnitY - GetEyeshotWidth(), 0);
	l_rect.RightBottom.X = min(sMgrUnitX + GetEyeshotWidth(), GetEyeshotCellCol() -1);
	l_rect.RightBottom.Y = min(sMgrUnitY + GetEyeshotWidth(), GetEyeshotCellLin() -1);

	return l_rect;
}

void SubMap::GetEyeshotCenter(Corsairs::Util::Point &pt)
{
	const Corsairs::Util::Rect	&m_area = GetRange();
	pt.X	=(pt.X - m_area.LeftTop.X) / GetEyeshotCellWidth();
	pt.Y	=(pt.Y - m_area.LeftTop.Y) / GetEyeshotCellHeight();
}

Corsairs::Util::Rect SubMap::GetHoldStateCell(Corsairs::Util::Point &pt, std::int32_t lRadius) const 
{
	const Corsairs::Util::Rect	&m_area = GetRange();
	Corsairs::Util::Rect l_rect;
	if (lRadius > 0)
	{
		l_rect.LeftTop.X = (pt.X - lRadius - m_area.LeftTop.X) / GetStateCellWidth();
		l_rect.LeftTop.Y = (pt.Y - lRadius - m_area.LeftTop.Y) / GetStateCellHeight();
		l_rect.RightBottom.X = (pt.X + lRadius - m_area.LeftTop.X) / GetStateCellWidth();
		l_rect.RightBottom.Y = (pt.Y + lRadius - m_area.LeftTop.X) / GetStateCellHeight();

		if (l_rect.LeftTop.X < 0) l_rect.LeftTop.X = 0;
		if (l_rect.RightBottom.X >= GetStateCellCol()) l_rect.RightBottom.X = GetStateCellCol() -1;
		if (l_rect.LeftTop.Y < 0) l_rect.LeftTop.Y = 0;
		if (l_rect.RightBottom.Y >= GetStateCellLin()) l_rect.RightBottom.Y = GetStateCellLin() -1;
	}
	else
	{
		l_rect.LeftTop.X = pt.X / GetStateCellWidth();
		l_rect.LeftTop.Y = pt.Y / GetStateCellHeight();
		l_rect.RightBottom.X = pt.X / GetStateCellWidth();
		l_rect.RightBottom.Y = pt.Y / GetStateCellHeight();
	}
	pt.X = (pt.X - m_area.LeftTop.X) / GetStateCellWidth();
	pt.Y = (pt.Y - m_area.LeftTop.Y) / GetStateCellHeight();

	return l_rect;
}

void SubMap::GetHoldStateCellCenter(Corsairs::Util::Point &pt)
{
	const Corsairs::Util::Rect	&m_area = GetRange();
	pt.X = (pt.X - m_area.LeftTop.X) / GetStateCellWidth();
	pt.Y = (pt.Y - m_area.LeftTop.Y) / GetStateCellHeight();
}

//===============Search===================================================================================
CCharacter*	SubMap::FindCharacter( std::uint32_t ulID, const Corsairs::Util::Point& point )
{
	CCharacter* pCha = NULL;
	std::int32_t	lRangeB[] = {point.X, point.Y, 0};
	std::int32_t	lRangeE[] = {enumRANGE_TYPE_CIRCLE, 10 * 100};
	BeginSearchInRange(lRangeB, lRangeE);
	while (pCha = GetNextCharacterInRange())
	{
		if(pCha->GetID() == ulID)
			break;
	}

	return pCha;
}

//=============================================================================
// plRangeBParam  defSKILL_RANGE_BASEP_NUM  
// plRangeEParam  defSKILL_RANGE_EXTEP_NUM  
// bIncludeHideEnti 
//=============================================================================
void SubMap::BeginSearchInRange(std::int32_t *plRangeBParam, std::int32_t *plRangeEParam, bool bIncludeHideEnti)
{
    m_sRangeCurMgrUnit = -1;
	m_pRangeCurEntiNode = 0;
	m_bIncludeHideEnti = bIncludeHideEnti;

	std::int32_t	lCx = plRangeBParam[0];
	std::int32_t	lCy = plRangeBParam[1];
	std::int32_t	lAngle = plRangeBParam[2];
	std::int32_t	lRangeType = plRangeEParam[0];

	std::int32_t	lUnitSX, lUnitEX, lUnitSY, lUnitEY;
	std::int32_t	lMaxRadius;
	if (lRangeType == enumRANGE_TYPE_STICK)
	{
		std::int32_t	lRadius = plRangeEParam[1];
		std::int32_t	lWidth = plRangeEParam[2];

		m_pCBaseRange = &m_CStickRange;
		m_CStickRange.setPos(lCx, lCy);
		m_CStickRange.setAngle(lAngle);
		m_CStickRange.setRadius(lRadius);
		m_CStickRange.setWidth(lWidth);

		lMaxRadius = (std::int32_t)sqrt(double(lRadius * lRadius + (lWidth / 2) * (lWidth / 2)));
	}
	else if (lRangeType == enumRANGE_TYPE_FAN)
	{
		std::int32_t	lRadius = plRangeEParam[1];
		std::int32_t	lAngleD = plRangeEParam[2];

		m_pCBaseRange = &m_CFanRange;
		m_CFanRange.setPos(lCx, lCy);
		lAngle = lAngle - lAngleD / 2;
		if (lAngle < 0)
			lAngle += 360;
		m_CFanRange.setAngle(lAngle);
		m_CFanRange.setAngleStep(lAngleD);
		m_CFanRange.setRadius(lRadius);

		lMaxRadius = lRadius;
	}
	else if (lRangeType == enumRANGE_TYPE_SQUARE)
	{
		std::int32_t	lRadius = plRangeEParam[1];

		m_pCBaseRange = &m_CSquareCRange;
		m_CSquareCRange.setPos(lCx, lCy);
		m_CSquareCRange.setAngle(lAngle);
		m_CSquareCRange.setRadius(lRadius);

		lMaxRadius = lRadius;
	}
	else if (lRangeType == enumRANGE_TYPE_CIRCLE)
	{
		std::int32_t	lRadius = plRangeEParam[1];

		m_pCBaseRange = &m_CCircleRange;
		m_CCircleRange.setPos(lCx, lCy);
		m_CCircleRange.setRadius(lRadius);

		lMaxRadius = lRadius;
	}
	else
		m_pCBaseRange = 0;

	if (!m_pCBaseRange)
		return;

	m_lRangeCentUnit[0] = lCx / GetStateCellWidth();
	m_lRangeCentUnit[1] = lCy / GetStateCellHeight();

	lUnitSX = (lCx - lMaxRadius) / GetStateCellWidth();
	lUnitEX = (lCx + lMaxRadius) / GetStateCellWidth();
	lUnitSY = (lCy - lMaxRadius) / GetStateCellHeight();
	lUnitEY = (lCy + lMaxRadius) / GetStateCellHeight();
	lUnitSX = lUnitSX < 0 ? 0 : lUnitSX;
	lUnitEX = lUnitEX > GetStateCellCol() -1 ? GetStateCellCol() -1 : lUnitEX;
	lUnitSY = lUnitSY < 0 ? 0 : lUnitSY;
	lUnitEY = lUnitEY > GetStateCellLin() -1 ? GetStateCellLin() -1 : lUnitEY;

	m_sRangeMgrUnitNum = 0;
	std::int32_t	sx, sy, ex, ey;
	for (int i = lUnitSY; i <= lUnitEY; i++)
		for (int j = lUnitSX; j <= lUnitEX; j++)
		{
			sx = j * GetStateCellWidth();
			ex = sx + GetStateCellWidth() - 1;
			sy = i * GetStateCellHeight();
			ey = sy + GetStateCellHeight() - 1;
			if (m_pCBaseRange->RectHitTest(sx, sy, ex, ey)) // 
			{
				m_lRangeMgrUnit[m_sRangeMgrUnitNum][0] = j;
				m_lRangeMgrUnit[m_sRangeMgrUnitNum][1] = i;
				m_sRangeMgrUnitNum++;
				if (m_sRangeMgrUnitNum >= defRANGE_MGRUNIU_NUM)
				{
					//MessageBox(NULL, "", "", MB_OK);
					MessageBox(NULL, RES_STRING(GM_SUBMAP_CPP_00004), RES_STRING(GM_SUBMAP_CPP_00005), MB_OK);
					return;
				}
			}
		}
}

CCharacter* SubMap::GetNextCharacterInRange(void)
{
	if (!m_pCBaseRange)
		return 0;

Research:
	if (m_pRangeCurEntiNode)
		m_pRangeCurEntiNode = m_pRangeCurEntiNode->m_pCNext;

	while (!m_pRangeCurEntiNode)
	{
		m_sRangeCurMgrUnit++;
		if (m_sRangeCurMgrUnit >= m_sRangeMgrUnitNum)
			return 0;
		if (auto* cell = _stateCellGrid.Get(static_cast<short>(m_lRangeMgrUnit[m_sRangeCurMgrUnit][0]),
										   static_cast<short>(m_lRangeMgrUnit[m_sRangeCurMgrUnit][1]))) {
			m_pRangeCurEntiNode = cell->m_pCChaIn;
		}
	}

	if (m_pRangeCurEntiNode)
	{
		if (!m_bIncludeHideEnti)
		{
			CCharacter	*pCCha = m_pRangeCurEntiNode->m_pCCha;
			if (pCCha && pCCha->IsHide())
				goto Research;
			else
				return pCCha;
		}
		else
			return m_pRangeCurEntiNode->m_pCCha;
	}
	else
		return 0;
}

//=============================================================================
// BeginSearchInRange
//=============================================================================
bool SubMap::RangeAddState(std::uint8_t uchFightID, std::uint32_t ulSrcWorldID, std::int32_t lSrcHandle,
						   char chObjType, char chObjHabitat, char chEffType, int16_t *sStateParam)
{
	if (sStateParam[0] > AREA_STATE_MAXID || sStateParam[1] > SKILL_STATE_LEVEL)
		return false;

	if (!m_pCBaseRange)
		return false;

	CSkillStateRecord	*pSStateR = 0;
	pSStateR = GetCSkillStateRecordInfo(sStateParam[0]);
	if (!pSStateR)
		return false;

	std::int32_t	x, y;
	std::uint32_t	ulStartTick = GetTickCount();
	bool	bAddSuc;
	bool	bAlreadyHas;
	for (int16_t i = 0; i < m_sRangeMgrUnitNum; i++)
	{
		bAddSuc = false;
		bAlreadyHas = false;
		x = m_lRangeMgrUnit[i][0], y = m_lRangeMgrUnit[i][1];

		{
			auto* cell = _stateCellGrid.Get(static_cast<short>(x), static_cast<short>(y));
			if (cell && cell->m_CSkillState.HasState((std::uint8_t)sStateParam[0])) {
				bAlreadyHas = true;
			}
		}
		if (x == m_lRangeCentUnit[0] && y == m_lRangeCentUnit[1])
			bAddSuc = AddCellState(uchFightID, ulSrcWorldID, lSrcHandle, chObjType, chObjHabitat, chEffType, x, y, (std::uint8_t)sStateParam[0], (std::uint8_t)sStateParam[1], ulStartTick, sStateParam[2], pSStateR->chAddType, 1);
		else
			bAddSuc = AddCellState(uchFightID, ulSrcWorldID, lSrcHandle, chObjType, chObjHabitat, chEffType, x, y, (std::uint8_t)sStateParam[0], (std::uint8_t)sStateParam[1], ulStartTick, sStateParam[2], pSStateR->chAddType, 0);
		if (!bAlreadyHas && bAddSuc)
		{
			NotiStateCellToEyeshot((short)x, (short)y);
		}
	}

	return true;
}

bool SubMap::RangeAddState(Corsairs::Util::Rect *pSRange, std::uint8_t uchFightID, std::uint32_t ulSrcWorldID, std::int32_t lSrcHandle,
						   char chObjType, char chObjHabitat, char chEffType, int16_t *sStateParam)
{
	if (sStateParam[0] > AREA_STATE_MAXID || sStateParam[1] > SKILL_STATE_LEVEL)
		return false;

	CSkillStateRecord	*pSStateR = 0;
	pSStateR = GetCSkillStateRecordInfo(sStateParam[0]);
	if (!pSStateR)
		return false;

	std::int32_t	lUnitSX, lUnitEX, lUnitSY, lUnitEY, lUnitCX, lUnitCY;
	lUnitSX = pSRange->LeftTop.X / GetStateCellWidth();
	lUnitEX = pSRange->RightBottom.X / GetStateCellWidth();
	lUnitSY = pSRange->LeftTop.Y / GetStateCellHeight();
	lUnitEY = pSRange->RightBottom.Y / GetStateCellHeight();
	lUnitSX = lUnitSX < 0 ? 0 : lUnitSX;
	lUnitEX = lUnitEX > GetStateCellCol() -1 ? GetStateCellCol() -1 : lUnitEX;
	lUnitSY = lUnitSY < 0 ? 0 : lUnitSY;
	lUnitEY = lUnitEY > GetStateCellLin() -1 ? GetStateCellLin() -1 : lUnitEY;

	lUnitCX = lUnitSX + (lUnitEX - lUnitSX) / 2;
	lUnitCY = lUnitSY + (lUnitEY - lUnitSY) / 2;

	std::uint32_t	ulStartTick = GetTickCount();
	bool	bAddSuc;
	bool	bAlreadyHas;
	for (std::int32_t y = lUnitSY; y <= lUnitEY; y++)
		for (std::int32_t x = lUnitSX; x <= lUnitEX; x++)
		{
			bAddSuc = false;
			bAlreadyHas = false;

			{
				auto* cell = _stateCellGrid.Get(static_cast<short>(x), static_cast<short>(y));
				if (cell && cell->m_CSkillState.HasState((std::uint8_t)sStateParam[0])) {
					bAlreadyHas = true;
				}
			}
			if (y == lUnitCY && x == lUnitCX)
				bAddSuc = AddCellState(uchFightID, ulSrcWorldID, lSrcHandle, chObjType, chObjHabitat, chEffType, x, y, (std::uint8_t)sStateParam[0], (std::uint8_t)sStateParam[1], ulStartTick, sStateParam[2], pSStateR->chAddType, 1);
			else
				bAddSuc = AddCellState(uchFightID, ulSrcWorldID, lSrcHandle, chObjType, chObjHabitat, chEffType, x, y, (std::uint8_t)sStateParam[0], (std::uint8_t)sStateParam[1], ulStartTick, sStateParam[2], pSStateR->chAddType, 0);
			if (!bAlreadyHas && bAddSuc)
			{
				auto* cell = _stateCellGrid.Get(static_cast<short>(x), static_cast<short>(y));
				ActiveEyeshotCell(cell->m_pCEyeshotCell->m_sPosX, cell->m_pCEyeshotCell->m_sPosY);
				NotiStateCellToEyeshot((short)x, (short)y);
			}
		}

	return true;
}

void SubMap::NotiStateCellToEyeshot(int16_t sCellX, int16_t sCellY)
{
	auto* cell = _stateCellGrid.Get(sCellX, sCellY);
	if (!cell) {
		return;
	}

	auto pk = Corsairs::Net::Msg::serialize(Corsairs::Net::Msg::McAStateBeginSeeMessage{
		static_cast<int64_t>(sCellX), static_cast<int64_t>(sCellY),
		cell->m_CSkillState.BuildStateEntries()
	});

	Corsairs::Util::Rect	l_rect = GetEyeshot(cell->m_pCEyeshotCell->m_sPosX, cell->m_pCEyeshotCell->m_sPosY);
	Entity		*pCEnt;
	CCharacter	*pCCha;
	std::vector<CPlayer*> recipients;
	for (long y = l_rect.LeftTop.Y; y <= l_rect.RightBottom.Y; y++)
	{
		for (long x = l_rect.LeftTop.X; x <= l_rect.RightBottom.X; x++)
		{
			pCEnt = m_pCEyeshotCell[y][x].m_pCChaL;
			while (pCEnt)
			{
				pCCha = pCEnt->IsCharacter();
				if(pCCha->IsPlayerFocusCha())
				{
					recipients.push_back(pCCha->GetPlayer());
				}
				pCEnt = pCEnt->m_pCEyeshotCellNext;
			}
		}
	}
	SENDTOCLIENT(pk, recipients);
}

