void SubMap::ClearAllMonsterByName(const char* szMonsName)
{
	CCharacter	*pCCha;
	std::int32_t		lChaCount, lChaNum;
	CEyeshotCell	*pCEyeCell;
	for (int16_t y = 0; y < GetEyeshotCellLin(); y++)
	{
		for (int16_t x = 0; x < GetEyeshotCellCol(); x++)
		{
			pCEyeCell = &m_pCEyeshotCell[y][x];
			lChaCount = 0;
			lChaNum = pCEyeCell->GetChaNum();
			pCCha = pCEyeCell->m_pCChaL;

			while (pCCha)
			{
				if (++lChaCount > lChaNum)
				{
					//LG("", "[%d,%d] %d\n", pCEyeCell->m_sPosX, pCEyeCell->m_sPosY, lChaNum);
					ToLogService("errors", LogLevel::Error, "eyeshot cell[{},{}]practice entity number {}", pCEyeCell->m_sPosX, pCEyeCell->m_sPosY, lChaNum);
					break;
				}

				if (!pCCha->IsPlayerOwnCha())
				{
					if (!strcmp(pCCha->GetName(), szMonsName))
						pCCha->ResetLifeTime(1000);
				}

				if (pCCha->m_pCEyeshotCellNext)
					pCCha = pCCha->m_pCEyeshotCellNext->IsCharacter();
				else
					pCCha = 0;
			}
		}
	}
}

void SubMap::ClearAllCha()
{
	CEyeshotCell	*pCEyeCell;
	CCharacter		*pCCha, *pCProcCha;
	long			lChaCount, lChaNum;
	//LG("enter_map", " %s %d!\n", GetName(), GetCopyNO());
	ToLogService("map", "map {}(copyID {})start clean out all monsters", GetName(), GetCopyNO());
	m_CEyeshotCellL.BeginGet();
	while (pCEyeCell = m_CEyeshotCellL.GetNext())
	{
		lChaCount = 0;
		lChaNum = pCEyeCell->GetChaNum();
		pCCha = pCEyeCell->m_pCChaL;
		while (pCCha)
		{
			if (++lChaCount > lChaNum)
			{
				//LG("", "[%d,%d] %d\n", pCEyeCell->m_sPosX, pCEyeCell->m_sPosY, lChaNum);
				ToLogService("errors", LogLevel::Error, "eyeshot cell[{},{}]practice entity numbers {}", pCEyeCell->m_sPosX, pCEyeCell->m_sPosY, lChaNum);
				break;
			}

			pCProcCha = pCCha;
			if (pCCha->m_pCEyeshotCellNext)
				pCCha = pCCha->m_pCEyeshotCellNext->IsCharacter();
			else
				pCCha = 0;

			if(!pCProcCha->IsPlayerFocusCha())
			{
				pCProcCha->Free();
			}
			else
			{
				if (!pCProcCha->GetSubMap())
					//LG("", " %s(%s)[%d,%d] \n",
					ToLogService("errors", LogLevel::Error, "in the wind map notify character {}({})[{},{}] 's map is empty",
					pCProcCha->GetLogName(), pCProcCha->GetPlyCtrlCha()->GetLogName(), pCProcCha->GetPos().X, pCProcCha->GetPos().Y);

				//LG("enter_map", " %s  %s[%s]!\n", GetName(), pCProcCha->GetName(), pCProcCha->GetPlyMainCha()->GetName());
				ToLogService("map", "map {} close,clean out character {}[{}]!", GetName(), pCProcCha->GetName(), pCProcCha->GetPlyMainCha()->GetName());
				if (!pCProcCha->IsLiveing())
				{
					g_luaAPI.Call("Relive", pCProcCha);

					pCProcCha->m_chSelRelive = enumEPLAYER_RELIVE_NONE;
					pCProcCha->m_chReliveLv = 0;
					pCProcCha->BackToCityEx(true);
				}
				else
					pCProcCha->BackToCityEx();
			}
		}
		pCEyeCell->m_pCChaL = NULL;
	}
	//LG("enter_map", " %s %d !\n", GetName(), GetCopyNO());
	ToLogService("map", "map {}(copyID {})clean out monster succeed!", GetName(), GetCopyNO());
}

